  ('judicial-f0899a01-moex-00297', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於行政處分效力之敘述，下列何者錯誤？', '["相對人不自動履行行政處分規制之義務時，原則上行政機關不得對其行政執行", "下命處分一旦生效，即有執行力", "行政處分因其存續力而對後行政處分產生構成要件效力", "行政處分原則上受有效之推定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00298', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依實務見解，下列人事行政行為，何者非屬行政處分？', '["核定請假之決定", "核定先行停職之決定", "平時考核之不予敘獎決定", "年資部分不採計之決定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00299', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依實務之見解，關於公立學校與其教師間之法律關係，下列敘述何者錯誤？', '["公立學校與教師間，係以行政契約性質之聘約建立之公法法律關係", "公立學校與教師間，雖存在公法法律關係，惟仍可能在個別事件成立私法法律關係", "公立學校與教師間之關係，係透過契約而成立，停聘仍屬契約行為，非屬行政處分", "公立學校教師與學校間就解聘發生爭執，屬公法性質得提起行政訴訟"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00300', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於行政契約之敘述，下列何者正確？', '["行政契約非法律行為", "行政機關得單方決定契約之成立無須相對人同意", "行政契約屬於公權力行政", "行政契約成立後，原則上須經許可始生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00301', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依行政程序法規定，關於行政機關處理陳情，下列敘述何者正確？', '["受理機關認為人民之陳情有理由者，應採取適當之措施", "陳情之重要內容不明確者，受理機關應為不受理之決定", "依法得提起訴願之事項，受理機關得不予處理，無庸告知陳情人", "陳情僅得以書面為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00302', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '有關行政罰法上之一行為不二罰原則，下列敘述何者錯誤？', '["違法之事實是否為一行為，必須就具體個案之事實情節，依據行為人主觀之犯意、構成要件之實現等因 素綜合判斷決定", "倘行為人不同，或雖行為人相同但非屬同一行為，而係數行為違反同一或不同行政法上義務之規定者， 則應分別處罰", "乃為避免因法律規定之錯綜複雜，致人民之同一行為，遭受數個不同法律之處罰，而承受過度不利之後果", "違法之事實是否為一行為，係就法規與法規間之關連，或抽象事實予以抽象之判斷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00303', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依行政罰法規定，關於沒入，下列敘述何者錯誤？', '["沒入之物，除本法或其他法律另有規定者外，以屬於受處罰者所有為限", "不屬於受處罰者所有之物，因所有人之故意或重大過失，致使該物成為違反行政法上義務行為之工具者， 不得裁處沒入", "得沒入之物，受處罰者於受裁處沒入前，予以處分、使用或以他法致不能裁處沒入者，得裁處沒入其物 之價額", "得沒入之物，受處罰者於受裁處沒入後，予以處分、使用或以他法致不能執行沒入者，得追徵其物之價額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00304', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依司法院釋字第753號解釋意旨，違反全民健康保險醫事服務機構特約及管理辦法之違約記點，其法律性 質為下列何者？', '["事實行為", "警告性處分", "違約通知", "影響名譽之不利益處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00305', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '因正當防衛行為過當致違反行政法上之義務者，有關減輕罰鍰之處罰，下列何者正確？', '["不得逾法定罰鍰最高額之1/2，亦不得低於法定罰鍰最低額之1/2", "不得逾法定罰鍰最高額之1/2，亦不得低於法定罰鍰最低額之1/3", "不得逾法定罰鍰最高額之1/3，亦不得低於法定罰鍰最低額之1/2", "不得逾法定罰鍰最高額之1/3，亦不得低於法定罰鍰最低額之1/3"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
